const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);

const componentGroupBase = (items: Item[]): number => {
  const blocks = Math.floor(items.length / COMPONENT_BLOCK_SIZE);
  const singles = items.length % COMPONENT_BLOCK_SIZE;
  const singlesBase = items.reduce(
    (sum, item) => sum + basePremiumForItem(item),
    0,
  ) / items.length * singles;
  return blocks * COMPONENT_BLOCK_BASE + singlesBase;
};

const groupByType = (items: Item[]): Map<string, Item[]> => {
  const groups = new Map<string, Item[]>();
  for (const item of items) {
    const list = groups.get(item.type) ?? [];
    list.push(item);
    groups.set(item.type, list);
  }
  return groups;
};

const componentsTotal = (items: Item[], customer: Customer): number => {
  const groups = groupByType(items);
  let total = 0;
  for (const groupItems of groups.values()) {
    const groupBase = componentGroupBase(groupItems);
    total +=
      groupBase +
      surcharge(
        groupBase,
        isNewcomer(customer),
        NEWCOMER_PER_ITEM_SURCHARGE_RATE,
      );
  }
  return total;
};

export const quote = (input: QuoteInput): { premium: number } => {
  const components = input.items.filter(isComponent);
  const nonComponents = input.items.filter((item) => !isComponent(item));
  const nonComponentsTotal = nonComponents.reduce(
    (sum, item) => sum + premiumForItem(item, input.customer),
    0,
  );
  const itemsTotal =
    nonComponentsTotal + componentsTotal(components, input.customer);
  return { premium: Math.ceil(itemsTotal + PROCESSING_FEE) };
};

